Confirmed working, but if it were up to me I would simplify:

```ts
const validEmails = invitations.reduce<string[]>((acc, { email }) => {
	if (!validator.isEmail(email)) throw new Error();
	acc.push(email);
	return acc;
}, []);

const alreadySetUp = await Db.collections
	.User!.find({ where: { email: In(validEmails) } })
	.then((users) =>
		users.reduce<{ [key: string]: boolean }>((acc, cur) => {
			acc[cur.email] = !!cur.password;
			return acc;
		}, {}),
	);

const emailsToSend = validEmails.filter((email) => !alreadySetUp[email]);
```

